.filter-text { color: var(--color-primary); font-size: 26rpx; }
.filter-mask { position: fixed; top: 0; left: 0; right: 0; bottom: 0; background-color: rgba(0,0,0,0.4); z-index: 100; display: flex; align-items: flex-end; }
